function steamAuth(username, password) {
  return new Promise((resolve, reject) => {
    const xhr = new XMLHttpRequest();
    xhr.open('POST', 'https://steamcommunity.com/login/dologin');
    xhr.setRequestHeader('Content-Type', 'application/x-www-form-urlencoded');
    xhr.onreadystatechange = function() {
      if (xhr.readyState === 4) {
        if (xhr.status === 200) {
          const response = JSON.parse(xhr.responseText);
          if (response.success) {
            const sessionId = response.sessionid;
            const cookies = response.cookies;
            resolve({ sessionId, cookies });
          } else {
            reject(new Error('Login failed: ' + response.message));
          }
        } else {
          if (xhr.status === 401) {
            // Request a new login key
            steamAuth(username, password).then(resolve).catch(reject);
          } else {
            reject(new Error('Login failed: ' + xhr.statusText));
          }
        }
      }
    };
    xhr.send(`steam_username=${encodeURIComponent(username)}&steam_password=${encodeURIComponent(password)}&remember_login=1&donotcache=${new Date().getTime()}`);
  });
}
