package main

import (
	"crypto/rand"
	"crypto/rsa"
	"crypto/x509"
	"encoding/pem"
	"os"
)

func generateRSAKeyPair() (*rsa.PrivateKey, *rsa.PublicKey, error) {
	// Generate a new RSA key pair
	privateKey, err := rsa.GenerateKey(rand.Reader, 2048)
	if err != nil {
		return nil, nil, err
	}

	// Extract the public key
	publicKey := privateKey.PublicKey

	return privateKey, publicKey, nil
}

func saveKeyPairToFile(privateKey *rsa.PrivateKey, publicKey *rsa.PublicKey, privateKeyFilePath, publicKeyFilePath string) error {
	// Encode the private key to PEM format
	privateKeyPEM := &pem.Block{
		Type:  "RSA PRIVATE KEY",
		Bytes: x509.MarshalPKCS1PrivateKey(privateKey),
	}

	// Write the private key to a file
	err := os.WriteFile(privateKeyFilePath, pem.EncodeToMemory(privateKeyPEM), 0600)
	if err != nil {
		return err
	}

	// Encode the public key to PEM format
	publicKeyPEM := &pem.Block{
		Type:  "PUBLIC KEY",
		Bytes: x509.MarshalPKCS1PublicKey(publicKey),
	}

	// Write the public key to a file
	err = os.WriteFile(publicKeyFilePath, pem.EncodeToMemory(publicKeyPEM), 0644)
	if err != nil {
		return err
	}

	return nil
}

func main() {
	// Generate RSA key pair
	privateKey, publicKey, err := generateRSAKeyPair()
	if err != nil {
		panic(err)
	}

	// Save the key pair to files
	err = saveKeyPairToFile(privateKey, publicKey, "private_key.pem", "public_key.pem")
	if err != nil {
		panic(err)
	}

	fmt.Println("RSA key pair generated and saved successfully.")
}
