// GeneratePrivateKey generates a private key of the specified type and size.
// It returns the private key and an error if any occurs.
// If entropySource is provided, it will be used to generate random numbers.
func GeneratePrivateKey(keyType string, keySize int, entropySource rand.Source) (*rsa.PrivateKey, error) {
