	var err error

	switch keyType {
	case "rsa":
		privateKey, err = rsa.GenerateKey(entropySource, keySize)
		if err != nil {
			return nil, fmt.Errorf("failed to generate RSA private key: %w", err)
		}
	default:
		return nil, fmt.Errorf("unsupported key type: %s", keyType)
	}

	return privateKey, nil
}

func main() {
