        data = pd.read_csv(path)
    elif extension == 'json':
        data = pd.read_json(path)
    elif extension == 'xlsx':
        data = pd.read_excel(path)
    elif extension == 'pickle':
        data = pd.read_pickle(path)
    else:
        raise ValueError('File extension not supported')

