def test_check_active_kube_config_context():
    try:
        # Run the command to get the current active Kubernetes config context
        result = subprocess.run(['kubectl', 'config', 'current-context'], capture_output=True, text=True, check=True)

        # Check if the command was successful
        if result.returncode == 0:
            print("Checking active Kubernetes config context successful.")
            print("Active context:", result.stdout)
        else:
            print("Failed to check active Kubernetes config context.")
