// RouteDistinguisher represents a route distinguisher in BGP.
type RouteDistinguisher struct {
	ASN    int
	IP     string
}

// ParseRouteDistinguisher takes a string in the format "AS:IP" or "IP:AS" and returns a RouteDistinguisher object.
// The ASN should be a 32-bit unsigned integer and the IP should be a valid IPv4 or IPv6 address.
// If the input string is not in the correct format, it returns an error.
func ParseRouteDistinguisher(input string) (RouteDistinguisher, error) {
	parts := strings.Split(input, ":")
	if len(parts) != 2 {
		return RouteDistinguisher{}, fmt.Errorf("invalid format: %s", input)
	}

	// Parse the ASN
	ASN, err := strconv.Atoi(parts[0])
	if err != nil {
		return RouteDistinguisher{}, fmt.Errorf("invalid ASN: %s", parts[0])
	}
	if ASN < 0 || ASN > 4294967295 {
		return RouteDistinguisher{}, fmt.Errorf("ASN must be a 32-bit unsigned integer")
	}

	// Parse the IP
	IP := parts[1]
	if !isValidIP(IP) {
		return RouteDistinguisher{}, fmt.Errorf("invalid IP address: %s", IP)
	}

	return RouteDistinguisher{ASN: ASN, IP: IP}, nil
}

// isValidIP checks if the provided string is a valid IPv4 or IPv6 address.
func isValidIP(ip string) bool {
	if strings.Contains(ip, ":") {
		_, err := net.ParseIP(ip)
		return err == nil
	}
	_, err := net.ParseIP(ip)
	return err == nil
}

