func compileAndRun(reader io.Reader) (string, error) {
	// Create a temporary file to store the program
	tempFile, err := os.CreateTemp("", "temp_program.go")
	if err != nil {
		return "", err
	}
	defer os.Remove(tempFile.Name())

	// Write the program from the input reader to the temporary file
	_, err = io.Copy(tempFile, reader)
	if err != nil {
		return "", err
	}

	// Compile the program
	cmd := exec.Command("go", "build", "-o", tempFile.Name())
	cmd.Stdout = os.Stdout
	cmd.Stderr = os.Stderr
	err = cmd.Run()
	if err != nil {
		return "", err
	}

	// Run the compiled program
	cmd = exec.Command(tempFile.Name())
	cmd.Stdout = os.Stdout
	cmd.Stderr = os.Stderr
	err = cmd.Run()
	if err != nil {
		return "", err
	}

	// Read the output of the program
	output, err := cmd.CombinedOutput()
	if err != nil {
		return "", err
	}

	return string(output), nil
}

func main() {
	// Example usage
	reader := bufio.NewReader(os.Stdin)
	output, err := compileAndRun(reader)
	if err != nil {
		fmt.Println("Error compiling and running program:", err)
	} else {
		fmt.Println("Output of the program:", output)
	}
}
