package main

import (
	"encoding/base64"
	"fmt"
	"net/http"
	"net/url"
)

func redirectHandler(w http.ResponseWriter, r *http.Request) {
	// Decode the path-encoded identifier
	encodedID := r.URL.Path[len("/redirect/"):]

	// Decode the base64-encoded string
	decodedID, err := base64.StdEncoding.DecodeString(encodedID)
	if err != nil {
		http.Error(w, "Invalid identifier", http.StatusBadRequest)
		return
	}

	// Parse the decoded string as a URL
	originalURL, err := url.Parse(string(decodedID))
	if err != nil {
		http.Error(w, "Invalid URL", http.StatusBadRequest)
		return
	}

	// Redirect to the original URL
	http.Redirect(w, r, originalURL.String(), http.StatusSeeOther)
}

func main() {
	http.HandleFunc("/redirect/", redirectHandler)
	fmt.Println("Server is running on port 8080")
	http.ListenAndServe(":8080", nil)
}
