package main

import (
	"fmt"
	"regexp"
)

// Define a struct to hold the bytecode details
type Bytecode struct {
	Metrics   map[string]int
	Regexps   []*regexp.Regexp
	Strings   []string
	Disassembly []string
}

// Define a function to format the bytecode details into a string
func formatBytecode(bytecode *Bytecode) string {
	// Start the formatted string with the metrics
	var formatted string
	for key, value := range bytecode.Metrics {
		formatted += fmt.Sprintf("Metric: %s = %d\n", key, value)
	}

	// Add regexps
	formatted += "Regexps:\n"
	for _, regexp := range bytecode.Regexps {
		formatted += regexp.String() + "\n"
	}

	// Add strings
	formatted += "Strings:\n"
	for _, str := range bytecode.Strings {
		formatted += str + "\n"
	}

	// Add disassembly
	formatted += "Disassembly:\n"
	for _, line := range bytecode.Disassembly {
		formatted += line + "\n"
	}

	return formatted
}

func main() {
	// Example usage
	metrics := map[string]int{"instructions": 100, "branches": 20}
	regexps := []*regexp.Regexp{regexp.MustCompile(`[a-zA-Z]`), regexp.MustCompile(`\d+`)}
