package main

import (
	"errors"
	"fmt"
)

// Basket represents a shopping basket with a name and optional configuration.
type Basket struct {
	name      string
	config    Config
}

// Config represents the configuration of a basket.
type Config struct {
	MaxItems int
}

// NewBasket creates a new basket with a name and optional configuration.
// It validates the basket name and returns an error if the name is invalid.
func NewBasket(name string, config Config) (*Basket, error) {
	if len(name) < 3 {
		return nil, errors.New("basket name must be at least 3 characters long")
	}
	return &Basket{name: name, config: config}, nil
}

func main() {
	// Example usage:
	basket, err := NewBasket("Grocery", Config{MaxItems: 10})
	if err != nil {
		fmt.Println("Error creating basket:", err)
		return
	}
	fmt.Println("Basket created:", basket.name)
}
