    private static final Logger logger = Logger.getLogger(UpdateSessionServlet.class.getName());

    @Override
    protected void doGet(HttpServletRequest request, HttpServletResponse response) throws ServletException, IOException {
        // Retrieve the session from the request
        HttpSession session = request.getSession();

        // Retrieve the parameters from the request
        String param1 = request.getParameter("param1");
        String param2 = request.getParameter("param2");

        // Update the session attributes
        session.setAttribute("param1", param1);
        session.setAttribute("param2", param2);

        // Log the result
        logger.info("Session updated with param1: " + param1 + ", param2: " + param2);

        // Optionally, send a response back to the client
        response.getWriter().println("Session updated successfully.");
    }
}
