function replaceElementWithForm(elementId) {
    const element = document.getElementById(elementId);
    if (!element) {
        console.error(`Element with ID ${elementId} not found.`);
        return;
    }

    // Create a form element
    const form = document.createElement('form');
    form.method = 'POST';
    form.action = '/submit-form'; // Replace with your server entspint

    // Create input fields for the form
    const nameInput = document.createElement('input');
    nameInput.type = 'text';
    nameInput.name = 'name';
    nameInput.placeholder = 'Name';

    const emailInput = document.createElement('input');
    emailInput.type = 'email';
    emailInput.name = 'email';
    emailInput.placeholder = 'Email';

    const submitButton = document.createElement('button');
    submitButton.type = 'submit';
    submitButton.textContent = 'Submit';

    // Append input fields and button to the form
    form.appendChild(nameInput);
    form.appendChild(emailInput);
    form.appendChild(submitButton);

    // Replace the original element with the form
    element.parentNode.replaceChild(form, element);

    // Handle form submission asynchronously
    form.addEventListener('submit', async (event) => {
        event.preventDefault();
        const formData = new FormData(form);
        try {
            const response = await fetch(form.action, {
                method: 'POST',
                body: formData
            });
            const data = await response.json();
            alert(`Form submitted successfully! ${data.message}`);
            form.reset();
        } catch (error) {
            console.error('Error submitting form:', error);
            alert('There was an error submitting the form. Please try again.');
        }
    });
}
