function updateGrade(entryId, grade) {
    // Assuming the table is represented as an array of objects
    const table = [
        { id: 1, name: 'Alice', grade: 'A' },
        { id: 2, name: 'Bob', grade: 'B' },
        { id: 3, name: 'Charlie', grade: 'C' }
    ];

    // Find the entry to update
    const index = table.findIndex(entry => entry.id === entryId);

    if (index !== -1) {
        // Update the grade based on the type of grade
        if (typeof grade === 'string') {
            // Update text-based grade
            table[index].grade = grade;
        } else if (typeof grade === 'object' && grade instanceof File) {
            // Update image-based grade
            table[index].grade = grade;
        } else {
            throw new Error('Invalid grade type');
        }

        console.log('Grade updated successfully');
    } else {
        console.error('Entry not found');
    }

    // Return the updated table
    return table;
}
