function searchAll(input) {
  // Construct the URL with the search input
  const url = `https://example.com/search?query=${encodeURIComponent(input)}`;

  // Update the browser's URL
  window.history.pushState({}, '', url);

  // Fetch and display search results
  fetch(url)
    .then(response => response.json())
    .then(data => {
      // Assuming data contains members and entities
      const members = data.members;
      const entities = data.entities;

      // Display members
      const membersContainer = document.getElementById('members-container');
      membersContainer.innerHTML = ''; // Clear previous results
      members.forEach(member => {
        const memberElement = document.createElement('div');
        memberElement.textContent = member.name;
        membersContainer.appendChild(memberElement);
      });

      // Display entities
      const entitiesContainer = document.getElementById('entities-container');
      entitiesContainer.innerHTML = ''; // Clear previous results
      entities.forEach(entity => {
        const entityElement = document.createElement('div');
        entityElement.textContent = entity.name;
        entitiesContainer.appendChild(entityElement);
      });
    })
    .catch(error => {
      console.error('Error fetching search results:', error);
    });
}
