```javascript
function updateRegularExpressions(text) {
  // Split the text into an array of lines
  const lines = text.split('\n');

  // Filter out lines that do not start with 'const'
  const regexLines = lines.filter(line => line.startsWith('const'));

  // Initialize an array to hold the updated regular expressions
  const updatedRegexes = [];

  // Iterate over each regex line
  regexLines.forEach(line => {
    // Extract the name and the regular expression from the line
    const [name, regex] = line.split('=');

    // Trim any leading or trailing whitespace from the name and regex
    const cleanName = name.trim();
    const cleanRegex = regex.trim();

    // Add the updated regular expression to the array
    updatedRegexes.push(`${cleanName} = ${cleanRegex}`);
  });

  // Join the updated regular expressions back into a single string
  return updatedRegexes.join('\n');
}
