function updateFormFields(type, value) {
    var $form = $('#your-form-id'); // Replace with your form ID

    switch (type) {
        case 'text':
            $form.find('input[type="text"]').val(value);
            break;
        case 'textarea':
            $form.find('textarea').val(value);
            break;
        case 'select':
            $form.find('select').val(value);
            break;
        case 'checkbox':
            $form.find('input[type="checkbox"]').prop('checked', value);
            break;
        case 'radio':
            $form.find('input[type="radio"]').prop('checked', value);
            break;
        default:
            console.log('Unsupported field type:', type);
            break;
    }

    // Preview text based on the field type
    var previewText = '';
    switch (type) {
        case 'text':
        case 'textarea':
            previewText = 'You entered: ' + value;
            break;
        case 'select':
            previewText = 'You selected: ' + $form.find('select option:selected').text();
            break;
        case 'checkbox':
            previewText = 'You ' + (value ? 'checked' : 'unchecked') + ' the checkbox.';
            break;
        case 'radio':
            previewText = 'You selected: ' + $form.find('input[type="radio"]:checked').val();
            break;
        default:
            previewText = 'No preview available for this field type.';
            break;
    }

    // Display the preview text
    $('#preview').text(previewText);
}
