package main

import (
	"encoding/json"
	"fmt"
	"io/ioutil"
	"net/http"
)

// WeatherData represents the structure of weather data returned by the API.
type WeatherData struct {
	Temperature int    `json:"temperature"`
	Weather    string `json:"weather"`
}

// Get retrieves weather forecast data using the provided coordinates and time.
// It returns a slice of WeatherData and an error if any occurred.
func Get(latitude, longitude, time string) ([]WeatherData, error) {
	// Construct the API URL with the provided parameters.
	url := fmt.Sprintf("https://api.weatherapi.com/v1/current.json?key=YOUR_API_KEY&q=%s,%s&dt=%s", latitude, longitude, time)

	// Make a GET request to the weather API.
	resp, err := http.Get(url)
	if err != nil {
		return nil, err
	}
	defer resp.Body.Close()

	// Read the response body.
	body, err := ioutil.ReadAll(resp.Body)
	if err != nil {
		return nil, err
	}

	// Unmarshal the JSON response into a slice of WeatherData.
	var weatherData []WeatherData
	err = json.Unmarshal(body, &weatherData)
	if err != nil {
		return nil, err
	}

	return weatherData, nil
}

func main() {
	// Example usage of the Get function.
	weather, err := Get("37.7749", "-122.4194", "2023-10-01T12:00:00Z")
	if err != nil {
		fmt.Println("Error fetching weather data:", err)
		return
	}

	// Print the retrieved weather data.
	for _, data := range weather {
		fmt.Printf("Temperature: %d°C, Weather: %s\n", data.Temperature, data.Weather)
	}
}
