const fs = require('fs');
const path = require('path');

function getBlockDeviceInfo(ignoreDevices = [], ignoreMajors = []) {
  return new Promise((resolve, reject) => {
    fs.readdir('/sys/block', (err, devices) => {
      if (err) {
        return reject(err);
      }

      const deviceInfo = devices
        .filter(device => !ignoreDevices.includes(device))
        .map(device => {
          const devicePath = path.join('/sys/block', device);
          const major = parseInt(fs.readFileSync(`${devicePath}/dev`).toString().split(':')[0], 10);
          const minor = parseInt(fs.readFileSync(`${devicePath}/dev`).toString().split(':')[1], 10);
          const deviceType = fs.readFileSync(`${devicePath}/removable`).toString().trim() === '1' ? 'removable' : 'non-removable';
          return {
            device,
            major,
            minor,
            deviceType
          };
        })
        .filter(device => !ignoreMajors.includes(device.major));

      resolve(deviceInfo);
    });
  });
}
