async function compareImages(imagePath1, imagePath2) {
  const img1 = await sharp(imagePath1).metadata();
  const img2 = await sharp(imagePath2).metadata();

  if (img1.width !== img2.width || img1.height !== img2.height) {
    console.error('Images have different dimensions.');
    return false;
  }

  const img1Buffer = await sharp(imagePath1).raw().toBuffer();
  const img2Buffer = await sharp(imagePath2).raw().toBuffer();

