  const diffCount = diffPixels.reduce((count, pixel) => count + (pixel !== 0), 0);

  const similarity = (1 - diffCount / (img1.width * img1.height * 3)) * 100;
  console.log(`Similarity: ${similarity.toFixed(2)}%`);

  return similarity >= 95; // Adjust the similarity threshold as needed
