const { execSync } = require('child_process');

function executeCommand(command, input = null) {
  try {
    if (input) {
      // Use the `--input` option to pass input to the command
      const result = execSync(`${command} --input "${input}"`, { stdio: 'inherit' });
      return result.toString();
    } else {
      // Execute the command without input
      const result = execSync(command, { stdio: 'inherit' });
      return result.toString();
    }
  } catch (error) {
    console.error(`Error executing command: ${error.message}`);
    throw error;
  }
}

// Example usage:
