const { exec } = require('child_process');

function verifySSL(options) {
  const { cert, ca = [], port = 443, host = 'localhost' } = options;
  const caString = ca.map(cert => `-CAfile ${cert}`).join(' ');
  const command = `openssl s_client -connect ${host}:${port} -CApath ${caString} -verify_hostname ${host} -cert ${cert}`;

  return new Promise((resolve, reject) => {
    exec(command, (error, stdout, stderr) => {
      if (error) {
        reject(error);
      } else if (stderr.includes('Verify return code:')) {
        resolve(stdout);
      } else {
        reject(new Error('SSL verification failed'));
      }
    });
  });
}

// Example usage:
verifySSL({
  cert: 'path/to/your/certificate.pem',
  ca: ['path/to/ca1.pem', 'path/to/ca2.pem'],
  port: 8443,
  host: 'example.com'
}).then(result => {
  console.log(result);
}).catch(error => {
  console.error(error);
});
