function processImagesIntoTiles(imageUrls, options) {
  const { tileSize, padding, backgroundColor, margin, rotate } = options || {};
  const tiles = [];

  imageUrls.forEach(url => {
    const img = new Image();
    img.src = url;

    img.onload = () => {
      const canvas = document.createElement('canvas');
      canvas.width = tileSize;
      canvas.height = tileSize;

      const ctx = canvas.getContext('2d');
      ctx.fillStyle = backgroundColor || '#ffffff';
      ctx.fillRect(0, 0, canvas.width, canvas.height);

      ctx.drawImage(img, margin, margin, tileSize - 2 * margin, tileSize - 2 * margin);

      if (rotate) {
        ctx.save();
        ctx.translate(canvas.width / 2, canvas.height / 2);
        ctx.rotate(rotate * Math.PI / 180);
        ctx.drawImage(img, -tileSize / 2, -tileSize / 2, tileSize, tileSize);
        ctx.restore();
      }

      tiles.push(canvas.toDataURL('image/png'));
    };
  });

  return tiles;
}
