const fs = require('fs');
const path = require('path');
const exec = require('child_process').exec;

function rsync(source, destination, options = {}) {
  const { recursive = true, deleteFiles = false } = options;

  const command = `rsync ${recursive ? '-r' : ''} ${deleteFiles ? '-a' : ''} ${source} ${destination}`;

  return new Promise((resolve, reject) => {
    exec(command, (error, stdout, stderr) => {
      if (error) {
        return reject(new Error(`Rsync error: ${error.message}\nStdout: ${stdout}\nStderr: ${stderr}`));
      }
      resolve(stdout);
    });
  });
}

// Example usage:
rsync('/path/to/source', '/path/to/destination', { recursive: true, deleteFiles: true })
  .then(result => console.log('Rsync completed:', result))
  .catch(error => console.error('Rsync failed:', error));
