import configparser

class ConfigError(Exception):
    pass

class Config:
    def __init__(self, filename):
        self.config = configparser.ConfigParser()
        try:
            self.config.read(filename)
        except configparser.Error as e:
            raise ConfigError(f"Error reading configuration file: {e}")

    def get(self, section, option, default=None):
        if section not in self.config:
            raise ConfigError(f"Section '{section}' not found.")
        if option not in self.config[section]:
            raise ConfigError(f"Option '{option}' not found in section '{section}'.")
        return self.config[section][option]

    def get_int(self, section, option, default=None):
        try:
            return int(self.get(section, option, default))
        except ValueError:
            raise ConfigError(f"Option '{option}' in section '{section}' is not a valid integer.")

    def get_float(self, section, option, default=None):
        try:
            return float(self.get(section, option, default))
        except ValueError:
            raise ConfigError(f"Option '{option}' in section '{section}' is not a valid float.")

    def get_bool(self, section, option, default=None):
        value = self.get(section, option, default)
        if value.lower() in ['true', 'yes', '1']:
            return True
        elif value.lower() in ['false', 'no', '0']:
            return False
        else:
            raise ConfigError(f"Option '{option}' in section '{section}' is not a valid boolean value.")

    def get_list(self, section, option, default=None):
        value = self.get(section, option, default)
        if not value:
            return default
        return value.split(',')
