import React, { useState, useEffect } from 'react';

const RepositoryMatcher = ({ repositoryName, lines }) => {
  const [matchedLines, setMatchedLines] = useState([]);

  useEffect(() => {
    const filteredLines = lines.filter(line => line.match(repositoryName));
    setMatchedLines(filteredLines);
  }, [repositoryName, lines]);

  return (
    <div>
      <h2>Matched Lines in {repositoryName}</h2>
      <ul>
        {matchedLines.map((line, index) => (
          <li key={index}>
            {line}
            <a href={`https://github.com/yourusername/repository/blob/master/file.js#L${line.split(':').pop()}`}>
              View on GitHub
            </a>
          </li>
        ))}
      </ul>
    </div>
  );
};

export default RepositoryMatcher;
