)

type DailyTally struct {
	Date    string `json:"date"`
	Tally   int    `json:"tally"`
}

func getLastNDailyTallies(w http.ResponseWriter, r *http.Request) {
	// Extract the 'n' parameter from the URL
	nStr := r.URL.Query().Get("n")
	if nStr == "" {
		http.Error(w, "Missing 'n' parameter", http.StatusBadRequest)
		return
	}

	// Convert 'n' to an integer
	n, err := strconv.Atoi(nStr)
	if err != nil {
		http.Error(w, "Invalid 'n' parameter", http.StatusBadRequest)
		return
	}

	// Retrieve the last 'n' daily tallies from the database
	// Assume a function GetLastNDailyTallies is available
	dailyTallies, err := GetLastNDailyTallies(n)
	if err != nil {
		http.Error(w, "Failed to retrieve daily tallies", http.StatusInternalServerError)
		return
	}

	// Convert the daily tallies to JSON
	jsonData, err := json.Marshal(dailyTallies)
	if err != nil {
		http.Error(w, "Failed to marshal JSON", http.StatusInternalServerError)
		return
	}

	// Set the response headers
	w.Header().Set("Content-Type", "application/json")

	// Write the JSON response
	w.Write(jsonData)
}

func main() {
	http.HandleFunc("/last-tallies", getLastNDailyTallies)
	log.Fatal(http.ListenAndServe(":8080", nil))
}
