)

// GetHostsForGroup retrieves a mapping of hostnames to their IDs for a given group name,
// excluding hosts under maintenance.
func GetHostsForGroup(groupName string, hosts map[string][]string, maintenanceHosts map[string]bool) map[string]string {
	hostsMap := make(map[string]string)
	for hostname, hostIDs := range hosts {
		if !maintenanceHosts[hostname] {
			for _, id := range hostIDs {
				hostsMap[hostname] = id
			}
		}
	}
	return hostsMap
}

func main() {
	hosts := map[string][]string{
		"group1": {"host1", "host2", "host3"},
		"group2": {"host4", "host5"},
	}
	maintenanceHosts := map[string]bool{
		"host2": true,
		"host5": true,
	}

