// FetchRecordFromDB takes an HTTP request and a database connection, and returns a JSON response with the fetched record.
func FetchRecordFromDB(w http.ResponseWriter, r *http.Request) {
	// Parse the request parameters
	idStr := r.URL.Query().Get("id")
	if idStr == "" {
		http.Error(w, "ID parameter is required", http.StatusBadRequest)
		return
	}

	id, err := strconv.Atoi(idStr)
	if err != nil {
		http.Error(w, "Invalid ID", http.StatusBadRequest)
		return
	}

	// Connect to the database
	db, err := sql.Open("mysql", "user:password@tcp(127.0.0.1:3306)/database")
	if err != nil {
		http.Error(w, "Failed to connect to database", http.StatusInternalServerError)
		return
	}
	defer db.Close()

	// Prepare the SQL query
	query := "SELECT * FROM records WHERE id = ?"
	rows, err := db.Query(query, id)
	if err != nil {
		http.Error(w, "Failed to execute query", http.StatusInternalServerError)
		return
	}
	defer rows.Close()

	// Check if the record exists
	if !rows.Next() {
		http.Error(w, "Record not found", http.StatusNotFound)
		return
	}

	// Create a map to store the record data
	record := make(map[string]interface{})
	for rows.Next() {
		var (
			ID        int
			Name      string
			CreatedAt time.Time
			UpdatedAt time.Time
		)
		err := rows.Scan(&ID, &Name, &CreatedAt, &UpdatedAt)
		if err != nil {
			http.Error(w, "Failed to scan record", http.StatusInternalServerError)
			return
		}
		record["id"] = ID
		record["name"] = Name
		record["created_at"] = CreatedAt.Format(time.RFC3339)
		record["updated_at"] = UpdatedAt.Format(time.RFC3339)
	}

	// Send the response
	w.Header().Set("Content-Type", "application/json")
	json.NewEncoder(w).Encode(record)
}

func main() {
	http.HandleFunc("/record", FetchRecordFromDB)
	fmt.Println("Server is running on port 8080...")
	http.ListenAndServe(":8080", nil)
}
