const fs = require('fs');
const { Client } = require('pg');

async function insertEmailsIntoDatabase(jsonFilePath, connectionString) {
    // Read the JSON file
    const data = JSON.parse(fs.readFileSync(jsonFilePath, 'utf8'));
    const emails = data.emails;

    // Create a new PostgreSQL client
    const client = new Client({
        connectionString: connectionString
    });

    try {
        // Connect to the database
        await client.connect();

        // Prepare the SQL query to insert emails
        const insertQuery = `
            INSERT INTO consented_emails (email) 
            VALUES ($1) 
            ON CONFLICT (email) DO NOTHING;
        `;

        // Execute the query for each email
        for (const email of emails) {
            await client.query(insertQuery, [email]);
        }

        console.log(`${emails.length} emails inserted into the database.`);
    } catch (error) {
        console.error('Error inserting emails:', error);
    } finally {
        // Close the database connection
        await client.end();
    }
}

