app = Flask(__name__)

# In-memory storage for lost and found items
lost_found_items = {}

@app.route('/lost_found', methods=['GET', 'POST'])
def manage_lost_found():
    if request.method == 'GET':
        # Retrieve all lost and found items
        return jsonify(lost_found_items)

    elif request.method == 'POST':
        # Add a new lost and found item
        item_id = len(lost_found_items) + 1
        item = request.json
        lost_found_items[item_id] = item
        return jsonify({'item_id': item_id}), 201

if __name__ == '__main__':
    app.run(debug=True)
