describe('Config Parser Tests', () => {
  it('should parse a simple configuration file', () => {
    const config = parser.parse('config/simple.json');
    assert.equal(config.name, 'Example');
    assert.equal(config.version, '1.0');
    assert.equal(config.settings.theme, 'dark');
  });

  it('should handle nested configuration', () => {
    const config = parser.parse('config/nested.json');
    assert.equal(config.name, 'Nested Example');
    assert.equal(config.version, '2.0');
    assert.equal(config.settings.theme, 'light');
    assert.equal(config.settings.network.host, 'localhost');
    assert.equal(config.settings.network.port, 8080);
  });

  it('should throw an error for invalid JSON', () => {
    try {
      parser.parse('config/invalid.json');
    } catch (error) {
      assert.equal(error.message, 'Invalid JSON file');
    }
  });

  it('should handle missing configuration files', () => {
    try {
      parser.parse('config/missing.json');
    } catch (error) {
      assert.equal(error.message, 'Configuration file not found');
    }
  });
});
