function parseDotNotationUrlParams(url) {
    const params = new URLSearchParams(url.split('?')[1]);
    const obj = {};

    params.forEach((value, key) => {
        const keys = key.split('.');
        let current = obj;

        keys.forEach((keyPart, index) => {
            if (index === keys.length - 1) {
                current[keyPart] = value;
            } else {
                if (!current[keyPart]) {
                    current[keyPart] = {};
                }
                current = current[keyPart];
            }
        });
    });

    return obj;
}

// Test cases
function testParseDotNotationUrlParams() {
    const testCases = [
        { input: 'https://example.com?a.b=1&a.c.d=2', expected: { a: { b: 1, c: { d: 2 } } } },
        { input: 'https://example.com?x=5&y.z=10&y.a.b=20', expected: { x: 5, y: { z: 10, a: { b: 20 } } } },
        { input: 'https://example.com?a=10', expected: { a: 10 } },
        { input: 'https://example.com?no.parameters', expected: {} },
        { input: 'https://example.com?a[]=1&a[]=2&a[]=3', expected: { a: [1, 2, 3] } }
    ];

    testCases.forEach(({ input, expected }, index) => {
        const result = parseDotNotationUrlParams(input);
        console.log(`Test Case ${index + 1}:`, JSON.stringify(result) === JSON.stringify(expected) ? 'Passed' : 'Failed');
    });
}

testParseDotNotationUrlParams();
