                    os = new BufferedOutputStream(new FileOutputStream(targetFile));
                    is = zipFile.getInputStream(zipEntry);
                    byte[] buffer = new byte[4096];
                    int readLen = 0;
                    while ((readLen = is.read(buffer, 0, 4096)) > 0) {
                        os.write(buffer, 0, readLen);
                    }
                }
            } finally {
                close(is, os);
            }
        }
    } finally {
