            try (ZipInputStream zis = new ZipInputStream(new FileInputStream(destinationPath));
                 ZipEntry entry = zis.getNextEntry()) {
                while (entry != null) {
                    String fileName = entry.getName();
                    File newFile = new File(destinationPath + File.separator + fileName);
                    if (entry.isDirectory()) {
                        newFile.mkdirs();
                    } else {
                        try (FileOutputStream fos = new FileOutputStream(newFile)) {
                            byte[] buffer = new byte[4096];
                            int bytesRead;
                            while ((bytesRead = zis.read(buffer)) != -1) {
                                fos.write(buffer, 0, bytesRead);
                            }
                        }
                    }
                    zis.closeEntry();
                    entry = zis.getNextEntry();
                }
            }

            // Replace the old module files with the new ones
            File oldModuleDir = new File(destinationPath);
            File newModuleDir = new File(destinationPath + "_new");
            newModuleDir.mkdirs();
            File[] files = oldModuleDir.listFiles();
            if (files != null) {
                for (File file : files) {
                    File newFile = new File(newModuleDir, file.getName());
                    if (file.isDirectory()) {
                        newFile.mkdirs();
                    } else {
                        try (FileInputStream fis = new FileInputStream(file);
                             FileOutputStream fos = new FileOutputStream(newFile)) {
                            byte[] buffer = new byte[4096];
                            int bytesRead;
                            while ((bytesRead = fis.read(buffer)) != -1) {
                                fos.write(buffer, 0, bytesRead);
                            }
                        }
                    }
                }
            }

            // Rename the new module directory to replace the old one
            File oldModuleDir = new File(destinationPath);
            File newModuleDir = new File(destinationPath + "_new");
            oldModuleDir.delete();
            newModuleDir.renameTo(oldModuleDir);

            System.out.println("Module updated successfully.");

        } catch (IOException e) {
            System.err.println("Error updating module: " + e.getMessage());
        }
    }

    public static void main(String[] args) {
