import java.io.File;
import java.io.FileOutputStream;
import java.io.IOException;
import java.io.InputStream;
import java.nio.file.Files;
import java.nio.file.Path;
import java.nio.file.Paths;
import java.util.jar.JarEntry;
import java.util.jar.JarFile;

public class JarExtractor {

    public static void extractJar(String jarFilePath, String destinationDir) throws IOException {
        // Create the destination directory if it doesn't exist
        File destDir = new File(destinationDir);
        if (!destDir.exists()) {
            destDir.mkdirs();
        }

        // Open the JAR file
        try (JarFile jarFile = new JarFile(jarFilePath)) {
            // Get all entries in the JAR file
            Enumeration<JarEntry> entries = jarFile.entries();

            // Process each entry
            while (entries.hasMoreElements()) {
                JarEntry entry = entries.nextElement();
                String entryName = entry.getName();

                // Check if the entry is not in the META-INF directory
                if (!entryName.startsWith("META-INF/")) {
                    // Create the destination path
                    Path destPath = Paths.get(destinationDir, entryName);

                    // Create the directory structure if it doesn't exist
                    if (entry.isDirectory()) {
                        Files.createDirectories(destPath);
                    } else {
                        // Create the file and write the contents
                        try (InputStream is = jarFile.getInputStream(entry);
                             FileOutputStream fos = new FileOutputStream(destPath.toFile())) {
                            byte[] buffer = new byte[1024];
                            int len;
                            while ((len = is.read(buffer)) > 0) {
                                fos.write(buffer, 0, len);
                            }
                        }
                    }
                }
            }
        }
    }

    public static void main(String[] args) {
        try {
            extractJar("path/to/your/jarfile.jar", "path/to/destination/directory");
            System.out.println("JAR file extracted successfully.");
        } catch (IOException e) {
            e.printStackTrace();
        }
    }
}
