#include <stdio.h>
#include <string.h>
#include <arpa/inet.h>
#include <sys/socket.h>

// Define the structure for the socket connection
typedef struct {
    int sockfd;
    struct sockaddr_in local_addr;
} SocketConnection;

// Function to cache the local IP address and port
void cacheLocalAddress(SocketConnection *conn) {
    if (conn == NULL || conn->sockfd == -1) {
        fprintf(stderr, "Invalid socket connection structure\n");
        return;
    }

    // Get the local IP address and port
    socklen_t addr_len = sizeof(conn->local_addr);
    if (getsockname(conn->sockfd, (struct sockaddr *)&conn->local_addr, &addr_len) == -1) {
        perror("getsockname");
        return;
    }

    // Convert the IP address to a string
    char local_ip[INET_ADDRSTRLEN];
    inet_ntop(AF_INET, &conn->local_addr.sin_addr, local_ip, INET_ADDRSTRLEN);

    // Print the cached local IP and port
    printf("Cached Local IP: %s\n", local_ip);
    printf("Cached Local Port: %d\n", ntohs(conn->local_addr.sin_port));
}

int main() {
    // Example usage
    SocketConnection conn;
    conn.sockfd = socket(AF_INET, SOCK_STREAM, 0);
    if (conn.sockfd == -1) {
        perror("socket");
        return 1;
    }

    // Initialize the local address structure
    conn.local_addr.sin_family = AF_INET;
    conn.local_addr.sin_port = htons(8080);
    inet_pton(AF_INET, "127.0.0.1", &conn.local_addr.sin_addr);

    // Cache the local address and port
    cacheLocalAddress(&conn);

    // Close the socket
    close(conn.sockfd);

    return 0;
}
