            SSL_free(ssh_ssl);
            close(ssh_sock);
            close(sock);
            SSL_free(ssl);
            SSL_CTX_free(ctx);
            return 1;
        }

        // Perform SSL handshake for SSH
        if (SSL_connect(ssh_ssl) != 1) {
            ERR_print_errors_fp(stderr);
            SSL_free(ssh_ssl);
            close(ssh_sock);
            close(sock);
            SSL_free(ssl);
            SSL_CTX_free(ctx);
            return 1;
        }

        // Redirect Telnet traffic to SSH
        while (1) {
            char buf[1024];
            int len = SSL_read(ssl, buf, sizeof(buf) - 1);
            if (len <= 0) {
                break;
            }
            buf[len] = '\0';
            if (send(ssh_ssl, buf, len, 0) <= 0) {
                break;
            }
        }

        // Redirect SSH traffic to Telnet
        while (1) {
            char buf[1024];
            int len = SSL_read(ssh_ssl, buf, sizeof(buf) - 1);
            if (len <= 0) {
                break;
            }
            buf[len] = '\0';
            if (send(ssl, buf, len, 0) <= 0) {
                break;
            }
        }
    } else {
        // Redirect Telnet traffic directly
        while (1) {
            char buf[1024];
            int len = recv(sock, buf, sizeof(buf) - 1, 0);
            if (len <= 0) {
                break;
            }
            buf[len] = '\0';
            if (send(ssl, buf, len, 0) <= 0) {
                break;
            }
        }
    }

    // Close connections
    SSL_shutdown(ssl);
    SSL_free(ssl);
    close(sock);

    if (tunnel_enable[0] == 'e') {
        SSL_shutdown(ssh_ssl);
        SSL_free(ssh_ssl);
        close(ssh_sock);
    }

    // Clean up SSL context
    SSL_CTX_free(ctx);

    return 0;
}
